import { useEffect, useMemo, useRef, useState } from "react";

import { cashflowLayoutConfig } from "../cashflow-layout.config.ts";

const MIN_COLUMNS = 3;
const MAX_COLUMNS = 14;
const DEFAULT_COLUMNS = 7; // Fallback for initial render before measurement

export type UseCashflowLayoutConfigResult = {
  /** Reference to attach to the table container element */
  tableContainerRef: React.RefObject<HTMLDivElement>;
  /** Number of columns that fit in the current container width */
  columnCount: number;
};

/**
 * Hook for managing cashflow table layout measurements.
 *
 * Handles:
 * - Container width observation via ResizeObserver
 * - Column count calculation based on available width
 * - Responsive adjustment within min/max bounds
 */
export function useCashflowLayoutConfig(): UseCashflowLayoutConfigResult {
  // Reference to table container to calculate number of columns to fit the screen
  const tableContainerRef = useRef<HTMLDivElement>(null);

  const [containerWidth, setContainerWidth] = useState<number | null>(null);

  // Observe container width changes
  useEffect(() => {
    if (!tableContainerRef?.current) return;

    const resizeObserver = new ResizeObserver((entries) => {
      for (const entry of entries) {
        setContainerWidth(entry.contentRect.width);
      }
    });

    resizeObserver.observe(tableContainerRef.current);

    return () => {
      resizeObserver.disconnect();
    };
  }, [tableContainerRef]);

  // Calculate column count from container width and config
  const columnCount = useMemo(() => {
    if (containerWidth === null) {
      return DEFAULT_COLUMNS;
    }

    const { labelColumnWidth, dataColumnWidth } = cashflowLayoutConfig;
    const availableWidth = containerWidth - labelColumnWidth;
    const calculatedColumns = Math.floor(availableWidth / dataColumnWidth);

    return Math.max(MIN_COLUMNS, Math.min(MAX_COLUMNS, calculatedColumns));
  }, [containerWidth]);

  return {
    tableContainerRef,
    columnCount,
  };
}

