/**
 * Auto-Installation System for pi-lens
 *
 * Minimal auto-install: Core tools that run frequently. * Other tools require manual installation with clear instructions.
 *
 * Auto-install (8 tools): * - typescript-language-server (TypeScript LSP)
 * - pyright (Python LSP)
 * - ruff (Python linting) * - @biomejs/biome (JS/TS/JSON linting/formatting)
 * - madge (circular dependency detection) * - jscpd (duplicate code detection)
 * - @ast-grep/cli (structural code search)
 * - knip (dead code detection)
 * * Manual install required (25+ tools):
 * - yaml-language-server: npm install -g yaml-language-server * - vscode-json-languageserver: npm install -g vscode-langservers-extracted   ...    * - @prisma/language-server: npm install -g @prisma/language-server   ...    * - @vue/language-server: npm install -g @vue/language-server * - And all language-specific servers (gopls, rust-analyzer, etc.)
 *
 * Strategies:
 * - npm packages via npx/bun * - pip packages
 * - GitHub releases (for platform-specific binaries - not yet implemented)
 */ import { spawn } from "node:child_process";
import fs from "node:fs/promises";
import path from "node:path"; // Global installation directory for pi-lens tools
const TOOLS_DIR = path.join(process.cwd(), ".pi-lens", "tools"); // --- Tool Definitions --- interface ToolDefinition {
 id: string;
 name: string;
 checkCommand: string;
 checkArgs: string[]; installStrategy: "npm" | "pip" | "github";
 packageName?: string;
 binaryName?: string;   ...    const TOOLS: ToolDefinition[] = [
 // Core LSP servers
 {
 id: "typescript-language-server", name: "TypeScript Language Server",
 checkCommand: "typescript-language-server",
 checkArgs: ["--version"], installStrategy: "npm",
 packageName: "typescript-language-server",
 binaryName: "typescript-language-server",
 },
 { id: "pyright",
 name: "Pyright",
 checkCommand: "pyright",
 checkArgs: ["--version"],
 installStrategy: "npm", packageName: "pyright",
 binaryName: "pyright",
 },
 // Linting/formatting tools
 {
 id: "ruff",
 name: "Ruff",   ...    },
 {
 id: "biome",
 name: "Biome",
 checkCommand: "biome",
 checkArgs: ["--version"],
 installStrategy: "npm",   ...    id: "knip",
 name: "Knip",
 checkCommand: "knip",
 checkArgs: ["--version"],
 installStrategy: "npm", packageName: "knip",
 binaryName: "knip",
 },
];   ...    /**
 * Check if a command is available in PATH
 */
async function isCommandAvailable(
 command: string,   ...    /**
 * Check if a tool is installed (globally or locally)
 */   ...    const localBin = path.join(TOOLS_DIR, "node_modules", ".bin");
 const currentPath = process.env.PATH || "";   ...    /**
 * Check status of all managed tools
 */
export async function checkAllTools(): Promise<   ...    for (const tool of TOOLS) {
 const path = await getToolPath(tool.id);
 results.push({
 id: tool.id,
 name: tool.name, installed: path !== undefined,
 path,
 });
 }
 return results;
}

/**
 * Auto-loop engine for pi-lens fix and refactor commands.
 * * Provides automatic iteration without requiring the user to manually * re-run the command each time. Uses pi's event system (agent_end)
 * to trigger the next iteration automatically.
 * * IMPORTANT: Must be initialized at extension load time (in index.ts), * not lazily when the command is called. Event handlers need to be
 * registered early to catch agent_end events.
 */ import type {
 ExtensionAPI,
 ExtensionContext,
} from "@mariozechner/pi-coding-agent"; export interface LoopConfig {
 /** Unique identifier for this loop instance (e.g., "fix", "refactor") */ name: string;
 /** Maximum iterations before stopping */
 maxIterations: number; /** Command to run for each iteration */
 command: string; /** Patterns that indicate the loop should exit (e.g., "no more fixable issues") */
 exitPatterns: RegExp[]; /** Patterns that indicate completion with success */
 completionPatterns?: RegExp[]; /** Additional text to include when prompting for next iteration */
 continuePrompt?: string;
} export interface LoopState {
 active: boolean;
 iteration: number;
 maxIterations: number;
} export function createAutoLoop(
 pi: ExtensionAPI,
 config: LoopConfig,
): {
 start: (ctx: ExtensionContext) => void; stop: (ctx: ExtensionContext, reason: string) => void;
 getState: () => LoopState; setMaxIterations: (n: number) => void;
} {
 let state: LoopState = {
 active: false,
 iteration: 0,   ...    const updateStatus = (ctx: ExtensionContext) => {
 if (state.active) {
 ctx.ui.setStatus(
 `loop-${config.name}`, `${config.name} (${state.iteration + 1}/${state.maxIterations})`,
 );
 } else {   ...    const start = (ctx: ExtensionContext) => {
 if (state.active) {   ...    updateStatus(ctx);
 ctx.ui.notify(
 `🔄 Starting ${config.name} auto-loop (max ${state.maxIterations} iterations)...`, "info",
 );
 }; const getState = (): LoopState => ({ ...state });

 // --- Event Handlers (registered at module load time) --- // Handle user interruption (any manual input stops the loop)
 pi.on("input", async (event, ctx) => {   ...    // Handle end of agent turn → check if we should continue
 pi.on("agent_end", async (event, ctx) => {   ...    const hasExit = config.exitPatterns.some((p) => p.test(textContent));
 if (hasExit) {   ...    // Continue to next iteration - send command as follow-up
 updateStatus(ctx);
 const continueMsg = config.continuePrompt || `Run ${config.command} to continue.`;
 console.error( `[auto-loop] Triggering iteration ${state.iteration + 1}/${state.maxIterations}: ${config.command}`,
 ); pi.sendUserMessage(
 `🔄 Auto-loop (${state.iteration + 1}/${state.maxIterations}): ${continueMsg}`, { deliverAs: "followUp" },
 );
 }); return {
 start,
 stop,
 getState,
 setMaxIterations: (n: number) => {
 state.maxIterations = n;
 },
 };
}

